import React, { useEffect, useState } from 'react'
import {
    Card, Row, Col, Button,
    Space,
    Table, Modal, message, Tooltip
} from 'antd';

import {
    // UnorderedListOutlined,
    FileExcelOutlined,
    EyeOutlined,
    InfoCircleOutlined
} from '@ant-design/icons';
import FilterList from './FilterList';
import hasAuthObject from '../../helpers/hasAuthObject';
import Api from '../../helpers/api';
import handleApiError from '../../helpers/handleApiError';
import './table-color.css'


const api = new Api;
// setup auth object config for this page
const authobjectCfg = {
    view: 'stock-view', //button display detail
    create: 'stock-create', //button add
    update: 'stock-update', //button edit, 
    delete: 'stock-delete', //button delete
}

const List = (props) => {

    const [selectedRowKeys, setSelectedRowKeys] = useState([])
    const [loading, setLoading] = useState(false)
    const [data, setData] = useState([])
    const [pagination, setPagination] = useState({})
    const [filters, setFilters] = useState({})
    const [visibleModal, setVisibleModal] = useState(false)
    const [serialNumber, setSerialNumber] = useState(false)

    useEffect(() => {
        fetch({ ...filters })
    }, [filters])

    const fetch = (params = {}) => {
        setLoading(true)
        api.getStockList({ ...params })
            .then(response => {
                const data = response.data;

                let pagination = {}

                pagination.current = data.current_page
                pagination.total = data.total;
                pagination.pageSize = parseInt(data.per_page);

                setData(data.data)
                setPagination(pagination)
                setLoading(false)
            })
            .catch(error => {
                setLoading(false)
                handleApiError(error, props)
            })
    }

    const handleTableChange = (paginate, sorter) => {
        const pager = { ...pagination };
        pager.current = paginate.current;

        setPagination(pager)

        fetch({
            per_page: paginate.pageSize,
            page: paginate.current,
            sort_field: sorter.field,
            sort_order: sorter.order === 'ascend' ? 'asc' : 'desc',
            ...filters,
        });
    }

    const handleFilter = (value) => {
        setFilters(value)
    }

    const handleView = () => {
        if (selectedRowKeys.length > 1) {
            Modal.warning({
                title: `Anda memilih ${selectedRowKeys.length} data, silahkan hanya pilih 1 data`,
            });
        } else {
            props.history.push(`/stock/view/${selectedRowKeys[0]}`)
        }
    }

    const handleExport = () => {
        let params = { id: selectedRowKeys }

        api.exportStock({ ...params })
            .then((response) => {
                const { file, name } = response.data
                var a = document.createElement("a");
                a.href = file;
                a.download = name;
                document.body.appendChild(a);
                a.click();
                a.remove();
            })
            .catch(error => {
                if (error.response && error.response.data) {
                    const { errors } = error.response.data
                    message.error(errors.message);
                }
                handleApiError(error, props)
            });
    }

    const handleSerialClick = (e, id) => {
        showSerialModal(id)
    }

    const showSerialModal = (id) => {
        let params = { status: [1, 3] }
        api.getStockDetailSerialNumberByStockId(id, { ...params })
            .then(response => {
                setSerialNumber(response.data)
            })
            .catch(error => {
                console.log(error)
                handleApiError(error, props)
            })

        setVisibleModal(true)
    }

    const handleOk = () => {
        setVisibleModal(false)
    }

    const handleCancel = () => {
        setVisibleModal(false)
    }

    //on check table item
    const onSelectChange = (selectedRowKeys) => {
        setSelectedRowKeys(selectedRowKeys)
    }

    const rowSelection = {
        selectedRowKeys,
        onChange: onSelectChange,
    };

    const hasSelected = selectedRowKeys.length > 0;

    const columns = [
        {
            title: 'Plant',
            dataIndex: 'room',
            sorter: true,
            render: (room) => {
                return room.plant ? room.plant.name : '-'
            },
        },
        {
            title: 'Room',
            dataIndex: 'room',
            sorter: true,
            render: (room) => {
                if (room) { return room.name }
            },
        },
        {
            title: 'Material',
            dataIndex: 'material',
            sorter: true,
            render: (material) => {
                if (material) { return material.material_code }
            },
        },
        {
            title: 'Description',
            dataIndex: 'material',
            sorter: true,
            render: (material) => {
                if (material) { return material.description }
            },
        },
        {
            title: 'UoM',
            dataIndex: 'material',
            sorter: true,
            render: (material) => {
                if (material.uom) { return material.uom.name }
            },
        },
        {
            title: 'Ready Stock',
            dataIndex: 'stock',
            sorter: true,
            className: 'col-number',
        },
        {
            title: 'Quantity in Transit',
            dataIndex: 'quantity_in_transit',
            sorter: true,
            className: 'col-number',
        },
        {
            title: 'Minimum Stock',
            dataIndex: 'minimum_stock',
            sorter: true,
            className: 'col-number',
        },
        //     {
        //         title: 'Serial',
        //         dataIndex: 'material',
        //         render: (material, record) => (
        //             material.serial_number
        //                 ?
        //                 <Button
        //                     size="small"
        //                     type='primary'
        //                     onClick={(e) => handleSerialClick(e, record.id)}
        //                 >
        //                     <UnorderedListOutlined />
        //                 </Button>
        //                 : null
        //         ),
        //         width: 80
        //     }
    ]

    return (
        <Card>
            <Space direction="vertical" size="large" style={{ width: '100%' }}>
                <Row>
                    <Col lg={24}>
                        <FilterList filter={handleFilter} {...props} />
                    </Col>
                </Row>
                <Row>
                    <Col lg={24}>
                        <Space>
                            {hasAuthObject(authobjectCfg.view) &&
                                <Button
                                    onClick={() => handleView()}
                                    disabled={!hasSelected}
                                    icon={<EyeOutlined />}
                                >View</Button>
                            }
                            {hasAuthObject(authobjectCfg.view) &&
                                <Button
                                    onClick={() => handleExport()}
                                    disabled={!hasSelected}
                                    icon={<FileExcelOutlined />}
                                >Excel</Button>
                            }
                        </Space>
                    </Col>
                </Row>
                <Space>
                    <Tooltip placement="topLeft" title="Baris berwarna orange, stok tersedia kurang dari atau sama dengan stok minimal">
                        <Button shape="circle" icon={<InfoCircleOutlined />} />
                    </Tooltip>
                    <div style={{ display: 'inline-block', width: '15px', height: '10px', backgroundColor: 'orange' }} />
                    <div style={{ display: 'inline-block' }}>{'Stock <= Minimum Stock'}</div>
                </Space>
                <Row>
                    <Col lg={24} xs={24}>
                        <Table
                            loading={loading}
                            rowSelection={hasAuthObject(authobjectCfg.view) ? rowSelection : null}
                            columns={columns}
                            rowKey={record => record.id}
                            onChange={handleTableChange}
                            dataSource={data}
                            rowClassName={record => (record.stock <= record.minimum_stock && "orange")}
                            pagination={{
                                pageSizeOptions: ['20', '50', '100', '200'],
                                showSizeChanger: true,
                                showQuickJumper: true,
                                showTotal: (total, range) => `${range[0]}-${range[1]} of ${total} items`,
                                ...pagination
                            }}
                            scroll={{ y: 300, x: 1000 }} />
                    </Col>

                    <Modal
                        title="Serial Number"
                        visible={visibleModal}
                        onOk={handleOk}
                        onCancel={handleCancel}
                        footer={null}
                    >
                        {serialNumber.length > 0
                            ?
                            serialNumber.map((item, index) => (
                                <p key={index}>{item.serial_number}</p>
                            ))
                            : null}
                    </Modal>
                </Row>
            </Space>
        </Card>
    )
}

export default List