import React, { useEffect, useState } from 'react'
import {
    Row, Col, Button,
    Space, Collapse, DatePicker, Select, Checkbox
} from 'antd';

import {
    SearchOutlined,
    ReloadOutlined
} from '@ant-design/icons';
import moment from 'moment';
import Api from '../../helpers/api';
import handleApiError from '../../helpers/handleApiError';

// const { RangePicker } = DatePicker;
const { Option } = Select;
const api = new Api;

const FilterList = (props) => {

    const [plant, setPlant] = useState([])
    const [room, setRoom] = useState([])
    const [material, setMaterial] = useState([])
    const [valueSearch, setValueSearch] = useState({
        plant_id: [],
        room_id: [],
        material_id: [],
        ready_stock: false,
    })

    useEffect(() => {
        fetchPlant()
        fetchRoom()
        fetchMaterial()
        getDataBySavedFilter()
    }, [])

    // plant
    const fetchPlant = (q) => {
        api.getPlant({ q: q }).then(response => {
            const { data } = response.data;
            setPlant(data);
        }).catch(err => {
            console.log(err)
            handleApiError(err, props)
        })
    };

    const handleSearchPlant = (value) => {
        fetchPlant(value)
    }

    const handleChangePlant = (value) => {
        fetchPlant('')

        let newValue = { ...valueSearch }
        newValue['plant_id'] = value
        setValueSearch(newValue)
    }

    // room
    const fetchRoom = (q) => {
        api.getRoom({ q: q }).then(response => {
            const { data } = response.data;
            setRoom(data);
        }).catch(err => {
            console.log(err)
            handleApiError(err, props)
        })
    };

    const handleSearchRoom = (value) => {
        fetchRoom(value)
    }

    const handleChangeRoom = (value) => {
        fetchRoom('')
        let newValue = { ...valueSearch }
        newValue['room_id'] = value
        setValueSearch(newValue)
    }

    const fetchMaterial = (q) => {
        api.getMaterial({ q: q }).then(response => {
            const { data } = response.data;
            setMaterial(data);
        }).catch(err => {
            console.log(err)
            handleApiError(err, props)
        })
    };

    const handleSearchMaterial = (value) => {
        fetchMaterial(value)
    }

    const handleChangeMaterial = (value) => {
        fetchMaterial('')
        let newValue = { ...valueSearch }
        newValue['material_id'] = value
        setValueSearch(newValue)
    }

    const handleChangeReadyStock = (e) => {
        let newValue = { ...valueSearch }
        newValue['ready_stock'] = e.target.checked
        setValueSearch(newValue)
    }

    const getDataBySavedFilter = () => {
        const dataLocalStorage = JSON.parse(localStorage.getItem('filter_stock'))
        if (dataLocalStorage) {
            const filtersKeys = Object.keys(dataLocalStorage).length
            if (filtersKeys > 0) {
                if (dataLocalStorage.created_at) {
                    dataLocalStorage.created_at.map((item, index) => {
                        dataLocalStorage.created_at[index] = moment.utc(item, 'YYYY-MM-DD')
                    })
                }
                setValueSearch(dataLocalStorage)
                props.filter(dataLocalStorage)
            }
        }
    }

    const handleFilter = () => {
        if (valueSearch.created_at) {
            valueSearch.created_at.map((item, index) => {
                valueSearch.created_at[index] = moment.utc(item, 'YYYY-MM-DD')
            })
        }

        props.filter(valueSearch)
        // localStorage.setItem('filter_stock', JSON.stringify(valueSearch))
    }

    const handleReset = () => {
        // localStorage.removeItem('filter_stock');
        setValueSearch({})
        props.filter({})
    }

    return (
        <Collapse defaultActiveKey={["1"]}>
            <Collapse.Panel header={["Filter Stock"]} key="1" >
                <Row>
                    <Col lg={24}>
                        <Row>
                            <Col
                                style={{ padding: '5px' }} lg={6} xs={24}>
                                <Select
                                    mode="multiple"
                                    allowClear
                                    filterOption={false}
                                    style={{ width: '100%' }}
                                    onSearch={handleSearchPlant}
                                    onChange={handleChangePlant}
                                    name="plant"
                                    placeholder="Plant"
                                    value={valueSearch.plant_id}>

                                    {plant.map(item => (
                                        <Option key={item.id} value={item.id}>{item.name}</Option>
                                    ))}
                                </Select>
                            </Col>
                            <Col
                                style={{ padding: '5px' }} lg={6} xs={24}>
                                <Select
                                    mode="multiple"
                                    allowClear
                                    filterOption={false}
                                    style={{ width: '100%' }}
                                    onSearch={handleSearchRoom}
                                    onChange={handleChangeRoom}
                                    name="room"
                                    placeholder="Room"
                                    value={valueSearch.room_id}>

                                    {room.map(item => (
                                        <Option key={item.id} value={item.id}>{item.name}</Option>
                                    ))}
                                </Select>
                            </Col>
                            <Col
                                style={{ padding: '5px' }} lg={6} xs={24}>
                                <Select
                                    mode="multiple"
                                    allowClear
                                    filterOption={false}
                                    style={{ width: '100%' }}
                                    onSearch={handleSearchMaterial}
                                    onChange={handleChangeMaterial}
                                    name="material"
                                    placeholder="Material"
                                    value={valueSearch.material_id}>

                                    {material.map(item => (
                                        <Option key={item.id} value={item.id}>{item.material_code}</Option>
                                    ))}
                                </Select>
                            </Col>
                            <Col style={{ padding: '5px' }} lg={6} xs={24}>
                                <Checkbox
                                    onChange={handleChangeReadyStock}
                                    checked={valueSearch.ready_stock}>
                                    Ready Stock
                                </Checkbox>
                            </Col>
                        </Row>
                    </Col>
                </Row>

                <Space style={{ padding: '5px' }}>
                    <Button type="primary"
                        icon={<SearchOutlined />}
                        onClick={handleFilter}
                    >Search</Button>

                    <Button
                        icon={<ReloadOutlined />}
                        onClick={handleReset}
                    >Reset</Button>
                </Space>
            </Collapse.Panel>
        </Collapse>
    )
}

export default FilterList